def convert_to_tool_output(result: Any) -> ToolOutput:
    if isinstance(result, ToolOutput):
        return result
    if isinstance(result, str):
        # Detect code: has newlines and (indentation at line start or Python keywords)
        lines = result.splitlines()
        if len(lines) > 1:
            # Check indentation at line start (excluding empty lines)
            indented = any(line.startswith((' ', '      ')) for line in lines if line.strip())
            # Check Python keywords
            keywords = {'def', 'class', 'import', 'from', 'if', 'for', 'while', 'return', 'try', 'except', 'raise', 'with', 'as'}
            has_keywords = any(keyword in result.lower() for keyword in keywords)
            if indented or has_keywords:
                return CodeOutput(result)
        return TextOutput(result)
    if isinstance(result, list):
        if not result:
            return TextOutput('[]')
        # Check if list of dicts with consistent keys (table data)
        if all(isinstance(item, dict) for item in result):
            keys = [set(item.keys()) for item in result]
            if keys and all(k == keys[0] for k in keys):
                return TableOutput(result)
        # Check if list of file info dicts with 'path' key
        if all(isinstance(item, dict) and 'path' in item for item in result):
            return FileListOutput(result)
        # Default list representation
        return TextOutput(str(result))
    # Fallback: wrap in text output
    return TextOutput(str(result))

