        status = run_command(['git', 'status', '--porcelain'], cwd=cwd).strip()
        if not status:
            status = 'No changes'
    except Exception:
        status = 'Failed to get status'
    try:
        commits = run_command(['git', 'log', '--oneline', '-10'], cwd=cwd).strip()
        if not commits:
            commits = 'No commits'
    except Exception:
        commits = 'Failed to get commits'
